if($_SERVER['REQUEST_METHOD']==='POST'){ if(!validate_csrf_or_abort(false))$flashError='Pedido inválido.'; else try{ $action=$_POST['action']??'save'; $id=(int)($_POST['id']??0); if($action==='delete'){$pdo->prepare('UPDATE company_duty_sheets SET deleted_at=CURRENT_TIMESTAMP,updated_by=? WHERE id=?')->execute([$userId,$id]);gt_org_audit($pdo,$userId,'hr.job_descriptions.delete','company_duty_sheets',$id,[],[]);$flashSuccess='Caderno eliminado.';} elseif(in_array($action,['validate','archive'],true)){$status=$action==='validate'?'validated':'archived';$pdo->prepare('UPDATE company_duty_sheets SET status=?,updated_by=?,updated_at=CURRENT_TIMESTAMP WHERE id=?')->execute([$status,$userId,$id]);gt_org_audit($pdo,$userId,'hr.job_descriptions.'.$action,'company_duty_sheets',$id,[],['status'=>$status]);$flashSuccess='Estado atualizado.';} else { $data=[trim($_POST['title']??''),trim($_POST['job_role']??''),(int)($_POST['department_id']??0)?:null,(int)($_POST['responsible_user_id']??0)?:null,(int)($_POST['backup_user_id']??0)?:null,(int)($_POST['secondary_backup_user_id']??0)?:null,trim($_POST['status']??'draft'),trim($_POST['review_date']??'')?:null,trim($_POST['purpose']??''),trim($_POST['responsibilities']??''),trim($_POST['daily_tasks']??''),trim($_POST['weekly_tasks']??''),trim($_POST['monthly_tasks']??''),trim($_POST['annual_tasks']??''),trim($_POST['authority_text']??''),trim($_POST['kpis']??''),trim($_POST['systems_text']??''),trim($_POST['risks']??''),trim($_POST['notes']??'')]; if($id){$old=$pdo->prepare('SELECT * FROM company_duty_sheets WHERE id=?');$old->execute([$id]);$pdo->prepare('UPDATE company_duty_sheets SET title=?,job_role=?,department_id=?,responsible_user_id=?,backup_user_id=?,secondary_backup_user_id=?,status=?,review_date=?,purpose=?,responsibilities=?,daily_tasks=?,weekly_tasks=?,monthly_tasks=?,annual_tasks=?,authority_text=?,kpis=?,systems_text=?,risks=?,notes=?,updated_by=?,updated_at=CURRENT_TIMESTAMP WHERE id=?')->execute(array_merge($data,arr