$deps=$pdo->query('SELECT * FROM hr_departments ORDER BY name')->fetchAll(PDO::FETCH_ASSOC);$people=$pdo->query('SELECT id,name,is_active FROM users ORDER BY name')->fetchAll(PDO::FETCH_ASSOC);$q=trim($_GET['q']??'');$status=trim($_GET['status']??'');$where=['ds.deleted_at IS NULL'];$args=[]; if($q!==''){$where[]='(ds.title LIKE ? OR ds.job_role LIKE ? OR u.name LIKE ?)';$args[]="%$q%";$args[]="%$q%";$args[]="%$q%";} if($status!==''){$where[]='ds.status=?';$args[]=$status;} $st=$pdo->prepare('SELECT ds.*,d.name department_name,u.name responsible_name,b.name backup_name FROM company_duty_sheets ds LEFT JOIN hr_departments d ON d.id=ds.department_id LEFT JOIN users u ON u.id=ds.responsible_user_id LEFT JOIN users b ON b.id=ds.backup_user_id WHERE '.implode(' AND ',$where).' ORDER BY ds.updated_at DESC');$st->execute($args);$rows=$st->fetchAll(PDO::FETCH_ASSOC);
