ubstituto definido')?></strong></div><p><?=nl2br(h($r['responsibilities']??''))?></p><small>Revisão: <?=h($r['review_date']?:'Por definir')?> <?= $risks ? ' · Risco: '.h(implode(', ',$risks)) : '' ?></small><div class="mt-2"><a class="btn btn-outline-secondary btn-sm" href="?pdf=<?=$r['id']?>" target="_blank">PDF</a><form method="post" class="d-inline"><?=csrf_input()?><input type="hidden" name="id" value="<?=$r['id']?>"><button name="action" value="validate" class="btn btn-outline-success btn-sm">Validar</button><button name="action" value="archive" class="btn btn-outline-warning btn-sm">Arquivar</button><button name="action" value="delete" class="btn btn-outline-danger btn-sm">Eliminar</button></form></div></div></div></div><?php endforeach;?></div></div><?php require __DIR__.'/partials/footer.php'; ?>
